"""保存安徽2024一分一段表数据到CSV"""
import csv
import os

out_dir = os.path.join(os.path.dirname(__file__), 'score_rank_data')
os.makedirs(out_dir, exist_ok=True)

def save_csv(filename, data, category):
    csv_path = os.path.join(out_dir, f'2024_{filename}_{category}.csv')
    with open(csv_path, 'w', newline='', encoding='utf-8') as f:
        writer = csv.writer(f)
        writer.writerow(['score', 'count_this_score', 'cumulative_count'])
        for score, count, cum in data:
            writer.writerow([score, count, cum])
    print(f'✅ {filename}{category}: {len(data)} 条, {data[0][0]}-{data[-1][0]}, 累计 {data[-1][2]:,}')

